<template>
  <div>
    选相册和相机照片：<br />
    <input
      type="file"
      id="imgFileBs64"
      accept="image/*"
      @change="onLoadImgbs64()"
    />
  </div>
</template>

<script>
export default {
  name: "takePhoto", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      distinguishIMG: "",
      timeOutEvent: 0,
    };
  },
  computed: {},
  created() {},
  mounted() {
    /**
     *
     *
     **/
    $(function () {
      $("#touchArea").on({
        touchstart: function (e) {
          this.timeOutEvent = setTimeout(this.longPress, 500);
          e.preventDefault();
        },
        touchmove: function () {
          clearTimeout(timeOutEvent);
          this.timeOutEvent = 0;
        },
        touchend: function () {
          clearTimeout(this.timeOutEvent);
          if (this.timeOutEvent != 0) {
            alert("这是点击，请长按");
          }
          return false;
        },
      });
    });
  },
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //system 判断
    phoneType() {
      var u = navigator.userAgent;
      var isiOS = !!u.match(/\(i[^;]+;( U;)? CPU.+Mac OS X/);
      var isAndroid = u.indexOf("Android") > -1 || u.indexOf("Adr") > -1; //android终端
      if (isAndroid) {
        return "android";
      } else if (isiOS) {
        return "ios";
      } else {
        return "gg";
      }
    },
    /**

	拍照 返回原图和压缩后图片
	参数说明：
		 Callback		成功回调
		
		默认后置摄像头，用户在拍照界面手动选择前置拍照

	**/

    takePhotoNew() {
      navigator.ImageSelectPlugin.takePhoto(this.takePhotoCallback);
    },
    takePhotoCallback(e) {
      console.log("takePhotoNew： " + JSON.stringify(e));
      var fileUrl = e.data.compath;

      this.distinguishIMG = fileUrl;

      document.getElementById("backImage").src = fileUrl;

      var backImageUri = document.getElementById("imgUrlA");
      backImageUri.innerHTML = "图片路径:" + fileUrl;
    },

    //图片多选
    imageSelect() {
      navigator.ImageSelectPlugin.imageSelect(this.successCallback19);
    },
    successCallback19(v) {
      console.log("imageSelect:   " + JSON.stringify(v));

      var backImageUri = document.getElementById("imgUrlA");
      backImageUri.innerHTML = "图片路径:" + v.data.imageList;

      /**
		var imageList = v.data.imageList;
		console.log("imageList:   " +JSON.stringify(imageList));
		//把str按逗号分隔后,并把分隔后的内容存放在strArr数组中
		var imageArr = imageList.split(',');
		//遍历zhi并输出数组中的内容
		for(var i in imageArr){

		var imageUrl = imageArr[i]
		console.log("imageUrl:   " +imageList);

		}**/
    },

    /**
     *	方法：图片识别
     *   功能：调用插件，传入 本地 图片 URL 识别图中二维码
     **/

    distinguish() {
      //var filetext = document.getElementById("imgUrlA").innerText;
      //	var filetext2 = filetext.substr(5,filetext.length);
      alert("先点 拍照NEW，再点 识图： " + this.distinguishIMG);

      mam.navigator.ContentCompression.readPicture(
        successCallback,
        errorCallback,
        this.distinguishIMG
      );

      function successCallback(v) {
        var path = JSON.stringify(v);
        alert("图片中二维码信息：" + path);
      }
      function errorCallback(e) {
        var error = JSON.stringify(e);
        alert("errorCallback" + error);
      }
    },

    longPress() {
      var imgSrc = document.getElementById("touchArea").src;
      alert("开始识别在线二维码");

      timeOutEvent = 0;

      mam.navigator.ContentCompression.readPicture(
        successCallback,
        errorCallback,
        imgSrc
      );

      function successCallback(v) {
        var path = JSON.stringify(v);
        alert("图片中二维码信息：" + path);
      }
      function errorCallback(e) {
        var error = JSON.stringify(e);
        alert("errorCallback" + error);
      }
    },

    selectImage() {
      alert("图片单选 原生功能 不建议使用");
      mam.navigator.camera.getPicture(
        this.onSuccess3,
        this.onError,
        this.getCameraOptions3()
      );
    },

    upload() {
      var fileURI = document.getElementById("imgUrlA").innerText;
      var fileURI2 = fileURI.substr(5, fileURI.length);
      mam.navigator.appupload.appServerUpload(
        successCallback,
        errCallback,
        "SGCCINTSYS",
        "upload6",
        fileURI2,
        ""
      );
      function successCallback(obj) {
        alert("successCallback");
      }
      function errCallback(obj) {
        alert("errCallback");
      }
    },

    //清除界面上的数据
    clearData() {
      console.log("clear()");
      //清除图片
      var backImage = document.getElementById("backImage");
      backImage.style.display = "none";
      backImage.src = "";
      this.distinguishIMG = "";

      var backImageUri = document.getElementById("imgUrlA");
      backImageUri.innerHTML = "图片路径存放在此处";
    },

    takePhoto() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }

      //使用这边调用可以获取图像URL[和下面的只能调用一个方法]
      mam.navigator.camera.getPicture(
        onSuccess,
        onError,
        this.getCameraOptions()
      );

      //使用这边调用可以获取图像数据[和上面的只能调用一个方法]
      //mam.navigator.camera.getPicture(onSuccess2,onError,getCameraOptions2());

      function onSuccess(imageURI) {
        console.log("onSuccess() imageURI:" + imageURI);
        alert("onSuccess() imageURI:" + imageURI);
        //从这边返回数据
        var backImage = document.getElementById("backImage");
        backImage.style.display = "block";
        backImage.src = imageURI;

        this.distinguishIMG = imageURI;

        var backImageUri = document.getElementById("imgUrlA");
        backImageUri.innerHTML =
          "图片路径:" +
          imageURI.substr(0, 30) +
          "<br/>" +
          imageURI.substr(30, imageURI.length);
      }

      function onSuccess2(imageData) {
        console.log("onSuccess2() imageData:" + imageData);
        //从这边返回数据
        var backImage = document.getElementById("backImage");
        backImage.style.display = "block";
        var allData = "data:image/jpeg;base64," + imageData;
        backImage.src = allData;

        var backImageUri = document.getElementById("imgUrlA");
        //backImageUri.innerHTML = "图片数据:" + allData;
      }

      //参数为string类型
      function onError(cameraError) {
        console.log("onError() cameraError:" + cameraError);
        alert("onError() cameraError:" + cameraError);
      }
      console.log("test()--->end()");
    },
    onSuccess3(imageURI) {
      console.log("onSuccess() imageURI:" + imageURI);
      alert("onSuccess() imageURI:" + imageURI);
      //从这边返回数据
      var backImage = document.getElementById("backImage");
      backImage.style.display = "block";
      backImage.src = imageURI;

      this.distinguishIMG = imageURI;

      var backImageUri = document.getElementById("imgUrlA");
      backImageUri.innerHTML =
        "图片路径:" +
        imageURI.substr(0, 30) +
        "<br/>" +
        imageURI.substr(30, imageURI.length);
    },

    //参数为string类型
    onError(cameraError) {
      console.log("onError() cameraError:" + cameraError);
      alert("onError() cameraError:" + cameraError);
    },

    //获取相机操作参数,参数被封装在了json对象cameraOptions中了
    //参数说明
    //quality:取值为[0-100],表示图片质量，取值越低图片质量越差
    //destinationType:返回值的类型，取值如下
    //   Camera.DestinationType.DATA_URL:返回图片作为base64编码字符串
    //   Camera.DestinationType.FILE_URL:返回图片作为文件的URI
    //   Camera.DestinationType.NATIVE_URI:返回图片作为本地的URI{ios中assets-library://,android中content://}
    //sourceType:图片源类别
    //   Camera.PictureSourceType.PHOTOLIBRARY:图片库中
    //   Camera.PictureSourceType.CAMERA:从摄像机获取图片
    //   Camera.PictureSourceType.SAVEDPHOTOALBUM:已保存的相册
    //targetWidth:图片的宽度和高度
    //  用法:android中根据这个值来计算simpleSize
    //  未指定:如果设定的值<1默认后台插件设定成-1
    //targetHeight:
    //  指定:如果设定的值<1默认后台插件设定成-1

    //allowEdit:是否允许编辑[在android中此值没有起到作用，其它平台请参考插件源码]
    //encodingType:返回图片的格式
    //   Camera.EncodingType.JPEG{取值为0,表示返回JPEG格式的图片}
    //   Camera.EncodingType.PNG{取值为1,表示返回PNG格式的图片}
    //targetWidth:图片缩放宽度，以像素为单位
    //targetHeight:图片缩放高度，以像素为单位
    //mediaType:媒体类别，选择媒体的类别，sourceType:Camera.PictureSourceType.PHOTOLIBRARY/sourceType:Camera.PictureSourceType.SAVEDPHOTOALBUM
    //          值时，为此对象设定的值才有效。
    //         android中:sourceType的取值Camera.PictureSourceType.PHOTOLIBRARY和Camera.PictureSourceType.SAVEDPHOTOALBUM是一样的
    //mediaType取值:
    //        Camera.MediaType.PICTURE:[取值为0]表示选择图片
    //        Camera.MediaType.VIDEO:[取值为0]表示选择视屏
    //        Camera.MediaType.ALLMEDIA:[取值为0]表示为所有媒体
    //correctOrientation:正确的方向，旋转图片到正确的方向
    //saveToPhotoAlbum:是否保存到相册
    //   saveToPhotoAlbum取值:ture/false
    //popoverOptions:仅ios设备此值设定有效[对android或其它设备此属性无效]
    //cameraDirection:摄像头方向
    // Camera.Direction.BACK:后置摄像头
    // Camera.Direction.FRONT:前置摄像头
    getCameraOptions() {
      var cameraOptions = {
        quality: 100,
        destinationType: mam.navigator.camera.DestinationType.FILE_URI,
        sourceType: mam.navigator.camera.PictureSourceType.CAMERA,
        targetWidth: 1600,
        targetHeight: 1200,
        //allowEdit : true,
        encodingType: Camera.EncodingType.JPEG,
        saveToPhotoAlbum: true,
      };
      return cameraOptions;
    },

    getCameraOptions2() {
      var cameraOptions = {
        quality: 100,
        destinationType: mam.navigator.camera.DestinationType.DATA_URL,
        sourceType: mam.navigator.camera.PictureSourceType.CAMERA,
        targetWidth: 0,
        targetHeight: 0,
        //allowEdit : true,
        encodingType: Camera.EncodingType.JPEG,
        saveToPhotoAlbum: true,
      };
      return cameraOptions;
    },

    //打开本地相册
    getCameraOptions3() {
      var cameraOptions = {
        quality: 100,
        destinationType: mam.navigator.camera.DestinationType.NATIVE_URI,
        // sourceType : mam.navigator.camera.PictureSourceType.PHOTOLIBRARY,
        sourceType: mam.navigator.camera.PictureSourceType.SAVEDPHOTOALBUM,
        targetWidth: 0,
        targetHeight: 0,
        //allowEdit : true,
        encodingType: Camera.EncodingType.JPEG,
        saveToPhotoAlbum: true,
      };
      return cameraOptions;
    },

    /**
		路径解析(Android)
		参数说明：
			errorCallback		失败回调	"code":1 添加失败
	**/
    identifyPath() {
      alert("先拍照 或者选择图片  " + this.distinguishIMG);
      mam.navigator.ContentCompression.identifyPath(
        this.succCallback,
        this.errCallback,
        this.distinguishIMG
      );
    },

    succCallback(v) {
      alert("sdcard =1 content =2 ：" + JSON.stringify(v));
    },
    errCallback(e) {
      alert("errorCallback" + JSON.stringify(e));
    },

    ajaxUpload() {
      var formData = new FormData($("#uploadForm2")[0]);
      $.ajax({
        url: "https://mam1.ft-power.com.cn:10030/znptSYS/fileUpload",
        type: "POST",
        data: formData,
        async: false,
        cache: false,
        contentType: false,
        scriptCharset: "utf-8",
        processData: false,
        success: function (returndata) {
          document.getElementById("fileGride2").innerHTML = "";
          console.log("1returndata    " + returndata);
          alert("文件上传成功");
          getFileList();
        },
        error: function (returndata) {
          console.log("error= " + returndata);
        },
      });
    },
    /**
		图片压缩(Android)
		参数说明：
			errorCallback		失败回调	"code":1 添加失败
	**/
    getSmallPicture() {},

    /**
		图片裁剪	base64
		参数说明：	0：base64,		1：路径
	**/
    imageCatBS64() {
      var path = document.getElementById("imgUrlBs64").value;
      alert("base64 开始编辑  " + path);
      navigator.ImageSelectPlugin.cropImage(cutSuccessCallback, 0, path);
    },
    /**
		图片裁剪	相对路径
		参数说明：	0：base64,		1：路径
	**/
    imageCatR() {
      var path = document.getElementById("imgUrlR").value;
      alert("相对路径 " + path);
      navigator.ImageSelectPlugin.cropImage(cutSuccessCallback, 1, path);
    },
    /**
		图片裁剪	绝对路径
		参数说明：	0：base64,		1：路径	
	**/
    imageCatA() {
      var fileURI = document.getElementById("imgUrlA").innerText;
      var fileURI2 = fileURI.substr(5, fileURI.length);
      console.log("绝对路径1 " + fileURI2);
      navigator.ImageSelectPlugin.cropImage(cutSuccessCallback, 1, fileURI2);
    },

    cutSuccessCallback(e) {
      alert("cutSuccessCallback " + JSON.stringify(e));
    },

    //预览图片	bs64
    onLoadImgbs64() {
      var file = $("#imgFileBs64").get(0).files[0];
      var reader = new FileReader();
      //将文件以Data URL形式读入页面
      reader.readAsDataURL(file);
      reader.onload = function (e) {
        alert(this.result);
        //显示文件
        $("#showImgBs64").html(
          '<img src="' + this.result + '" alt="" width="30%" height="30%" />'
        );
        $("#imgUrlBs64").val(this.result);
      };
    },

    //预览图片	相对路径
    onLoadImgR() {
      var file = $("#imgFileR").get(0).files[0];
      var fileB = document.getElementById("imgFileR").value;
      $("#imgUrlR").val(fileB);

      var reader = new FileReader();
      //将文件以Data URL形式读入页面
      reader.readAsDataURL(file);
      reader.onload = function (e) {
        //显示文件
        $("#showImgR").html(
          '<img src="' + this.result + '" alt="" width="30%" height="30%" />'
        );
      };
    },

    /**
单文件上传	1
参数说明：
	successCallback		成功回调
	errorCallback		失败回调
	appCode				应用编码
	appServerCode		应用服务编码
	path				本地文件路径	字符串
	params				上传参数  key:value
**/
    appServerUpload(id) {
      var appCode = "SGCCINTSYS";
      var path = document.getElementById("imgUrlR").value;
      var params = { param1: id, param2: "这是param2      appServerUpload" };
      alert("文件路径：" + path);
      mam.navigator.appfilemanage.appServerUpload(
        fileDownloadCallback,
        fileDownloaderrCallback,
        appCode,
        id,
        path,
        params
      );
    },
    fileDownloadCallback(obj) {
      console.log(
        "fileDownloadCallback  下载文件  回调    " + JSON.stringify(obj)
      );
      onDeviceReady();
    },
    fileDownloaderrCallback(obj) {
      console.log(
        "fileDownloaderrCallback  下载文件  回调    " + JSON.stringify(obj)
      );
      onDeviceReady();
    },
  },
};
</script>
<style lang='css' scoped>
